/**
 * Converts an ordinal to a card index based on the note type
 * For cloze note types, we need to find the index of the ordinal in the list of cloze numbers
 * For regular note types, the ordinal is the index
 */
private fun CardTemplatePreviewer.ordinalToCardIndex(col: Collection, ordinal: Int): Int {
    if (mEditedNotetype == null) {
        return 0
    }
    return when {
        mEditedNotetype!!.isCloze -> {
            // For cloze notes, create a temporary note to get the cloze numbers
            val tempNote = col.newNote(mEditedNotetype!!)
            val fieldValues = getBundleEditFields(mNoteEditorBundle)
            for (i in 0 until minOf(fieldValues.size, tempNote.fields.size)) {
                tempNote.setField(i, fieldValues[i])
            }
            val clozeNumbers = col.clozeNumbersInNote(tempNote)
            val index = clozeNumbers.indexOf(ordinal + 1)
            if (index >= 0) index else 0
        }
        else -> ordinal
    }
}"}

